"use client";

import React, { useState, useEffect } from "react";
import { Search, Filter, X } from "lucide-react";
import Fuse from "fuse.js";
import { motion, AnimatePresence } from "framer-motion";
import DoctorCard from "./DoctorCard.jsx";

export default function DirectoryView() {
  const [doctors, setDoctors] = useState([]);
  const [filteredDoctors, setFilteredDoctors] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedDept, setSelectedDept] = useState(null);
  const [fuseInstance, setFuseInstance] = useState(null);
  const [departments, setDepartments] = useState([]);

  useEffect(() => {
    fetch("/doctors.json")
      .then(res => res.json())
      .then(data => {
        setDoctors(data);
        setFilteredDoctors(data);
        
        const fuseOptions = {
          threshold: 0.4,
          distance: 100,
          keys: [
            { name: "name", weight: 0.7 },
            { name: "department", weight: 0.3 }
          ]
        };
        setFuseInstance(new Fuse(data, fuseOptions));
        
        const depts = [...new Set(data.map(d => d.department))];
        setDepartments(depts);
      })
      .catch(err => console.error(err));
  }, []);

  useEffect(() => {
    if (!fuseInstance) return;

    let results = doctors;

    if (searchTerm.trim()) {
      results = fuseInstance.search(searchTerm).map(r => r.item);
    }

    if (selectedDept) {
      results = results.filter(d => d.department === selectedDept);
    }

    setFilteredDoctors(results);
  }, [searchTerm, selectedDept, fuseInstance, doctors]);

  return (
    <div className="w-full space-y-10">
      {/* Search and Filters */}
      <div className="flex flex-col items-center gap-6 w-full">
        <div className="relative w-full max-w-[480px]">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input
            type="text"
            placeholder="Search by name or department..."
            className="search-input w-full pl-12"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap justify-center gap-2">
          <button
            onClick={() => setSelectedDept(null)}
            className={`pill-chip ${!selectedDept ? "bg-indigo-600 text-white" : "bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400"}`}
          >
            All Categories
          </button>
          {departments.map(dept => (
            <button
              key={dept}
              onClick={() => setSelectedDept(dept === selectedDept ? null : dept)}
              className={`pill-chip ${selectedDept === dept ? "bg-indigo-600 text-white" : "bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700"}`}
            >
              {dept}
            </button>
          ))}
        </div>
      </div>

      {/* Results Section */}
      <div className="pb-12">
        <div className="flex items-center justify-between mb-6">
          <p className="text-sm font-medium text-slate-500">
            Showing {filteredDoctors.length} results
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <AnimatePresence>
            {filteredDoctors.map((doc, idx) => (
              <DoctorCard key={doc.email || idx} doctor={doc} />
            ))}
          </AnimatePresence>
        </div>

        {filteredDoctors.length === 0 && (
          <div className="py-20 text-center">
            <p className="text-slate-400">No doctors found matching your criteria.</p>
          </div>
        )}
      </div>
    </div>
  );
}
